import { useState } from 'react';
import { CheckCircle2, Circle, Play, XCircle } from 'lucide-react';

export function PlanApprovalCard() {
  const [steps, setSteps] = useState([
    { id: 1, text: "Initialize cargo compilation check", done: true },
    { id: 2, text: "Execute database integration unit tests", done: true },
    { id: 3, text: "Push commit changes to origin main", done: false }
  ]);
  const [status, setStatus] = useState("pending"); // pending, approved, rejected

  const toggleStep = (id) => {
    if (status !== "pending") return;
    setSteps((prev) => 
      prev.map((step) => step.id === id ? { ...step, done: !step.done } : step)
    );
  };

  return (
    <div className="w-full max-w-md mx-auto border border-border bg-card text-card-foreground p-6 rounded-2xl shadow-xl">
      <div className="flex items-center justify-between mb-4 border-b border-border pb-4">
        <div>
          <h4 className="font-bold tracking-tight text-foreground">AI Agent Execution Plan</h4>
          <p className="text-xs text-muted-foreground mt-0.5">Review and authorise next tasks</p>
        </div>
        <span className={`text-xs px-2 py-0.5 rounded-full font-semibold uppercase tracking-wider ${
          status === "approved"
            ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20'
            : status === "rejected"
            ? 'bg-rose-500/10 text-rose-500 border border-rose-500/20'
            : 'bg-amber-500/10 text-amber-500 border border-amber-500/20'
        }`}>
          {status}
        </span>
      </div>

      {/* Plan Steps Checklist */}
      <div className="space-y-3 mb-6">
        {steps.map((step) => (
          <div 
            key={step.id}
            onClick={() => toggleStep(step.id)}
            className={`flex items-center gap-3 p-3 rounded-xl border border-border/60 bg-muted/20 transition-all ${
              status === "pending" ? 'cursor-pointer hover:bg-muted/50' : 'opacity-80'
            }`}
          >
            {step.done ? (
              <CheckCircle2 className="h-5 w-5 text-emerald-500 shrink-0" />
            ) : (
              <Circle className="h-5 w-5 text-muted-foreground shrink-0" />
            )}
            <span className={`text-sm ${step.done ? 'line-through text-muted-foreground' : 'text-foreground'}`}>
              {step.text}
            </span>
          </div>
        ))}
      </div>

      {/* Action Authorisations */}
      {status === "pending" ? (
        <div className="flex items-center gap-3">
          <button
            onClick={() => setStatus("rejected")}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-semibold border border-border hover:bg-muted text-foreground transition-all"
          >
            <XCircle className="h-4 w-4 text-rose-500" />
            <span>Reject</span>
          </button>

          <button
            onClick={() => setStatus("approved")}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-bold bg-primary hover:bg-primary/95 text-primary-foreground shadow-md transition-all"
          >
            <Play className="h-4 w-4 fill-current" />
            <span>Approve</span>
          </button>
        </div>
      ) : (
        <div className="text-center text-xs text-muted-foreground font-mono">
          {status === "approved" ? "✓ Tasks authorised for runner execution." : "✗ Plan rejected. Re-diagnosing errors..."}
        </div>
      )}
    </div>
  );
}

