import { useState } from 'react';
import { FileCode2, GitMerge } from 'lucide-react';

export function PromptDiffView() {
  const [isSplit, setIsSplit] = useState(true);

  const diffLines = [
    { type: "rem", text: "- cargo build" },
    { type: "add", text: "+ cargo build --release" },
    { type: "unchanged", text: "  cargo test" }
  ];

  return (
    <div className="w-full max-w-xl mx-auto border border-border bg-card rounded-2xl overflow-hidden shadow-xl text-foreground">
      {/* Diff Header Controls */}
      <div className="flex items-center justify-between p-4 border-b border-border bg-muted/20">
        <div className="flex items-center gap-2">
          <FileCode2 className="h-5 w-5 text-primary" />
          <span className="text-sm font-bold tracking-tight">Execution Command Diff</span>
        </div>

        <button
          onClick={() => setIsSplit(!isSplit)}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-border text-xs font-semibold hover:bg-muted transition-colors"
        >
          <GitMerge className="h-3.5 w-3.5" />
          <span>{isSplit ? "Unified View" : "Split View"}</span>
        </button>
      </div>

      {/* Diff Code Window */}
      <div className="p-4 bg-neutral-950 font-mono text-xs overflow-x-auto">
        {isSplit ? (
          <div className="grid grid-cols-2 gap-4 divide-x divide-white/5">
            {/* Left Column (Removals) */}
            <div className="space-y-1.5">
              <span className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider block mb-2">Original</span>
              {diffLines.filter((l) => l.type !== "add").map((l, i) => (
                <div key={i} className={`p-1 rounded ${l.type === "rem" ? 'bg-rose-500/10 text-rose-400 border-l-2 border-rose-500' : 'text-neutral-500'}`}>
                  {l.text}
                </div>
              ))}
            </div>
            {/* Right Column (Additions) */}
            <div className="space-y-1.5 pl-4">
              <span className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider block mb-2">Revised</span>
              {diffLines.filter((l) => l.type !== "rem").map((l, i) => (
                <div key={i} className={`p-1 rounded ${l.type === "add" ? 'bg-emerald-500/10 text-emerald-400 border-l-2 border-emerald-500' : 'text-neutral-500'}`}>
                  {l.text}
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-1.5">
            {diffLines.map((line, idx) => (
              <div 
                key={idx}
                className={`p-1.5 rounded border-l-2 ${
                  line.type === "add"
                    ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500'
                    : line.type === "rem"
                    ? 'bg-rose-500/10 text-rose-400 border-rose-500'
                    : 'text-neutral-400 border-transparent'
                }`}
              >
                {line.text}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
